const input = $input.first().json;
const req = input.body || input;

if (req.debug === true) {
  return {
    json: {
      is_debug: true,
      status: 'debug',
      message: 'Agent orchestrator v4.0 is working!',
      features: [
        'multi-provider', 'hitl-approval', 'plan-mode', 'todo-tracking',
        'session-checkpoint', 'background-tasks', 'async-execution',
        'task-persistence', 'retry-logic', 'context-management', 'streaming-responses',
        'parallel-tool-execution', 'tool-result-caching', 'smart-rate-limiting', 'cost-token-tracking',
        'conversation-memory', 'tool-pipelines', 'webhook-notifications', 'agent-templates',
        'multi-agent-orchestration', 'knowledge-base-rag', 'scheduled-tasks', 'tool-plugins',
        'agent-learning', 'workflow-recording', 'smart-context-injection', 'inter-agent-communication',
        'agent-personas', 'goal-decomposition', 'tool-macros', 'audit-trail', 'adaptive-behavior',
        'grep', 'glob', 'web_search', 'git_status', 'web_fetch', 'file_write', 'file_edit'
      ],
      version: '4.0.0',
      agent_templates: ['coder', 'researcher', 'analyst', 'writer', 'devops', 'orchestrator'],
      agent_personas: ['senior_engineer', 'rapid_prototyper', 'research_analyst', 'devops_specialist'],
      builtin_pipelines: ['find_and_read', 'search_and_extract', 'backup_file'],
      builtin_macros: ['backup_and_edit', 'git_safe_commit', 'find_replace_all', 'analyze_codebase'],
      v40_features: {
        personas: 'Rich personality definitions with traits, expertise, communication style',
        goals: 'Goal decomposition into sub-goals with dependency graphs',
        macros: 'Reusable multi-tool sequences that execute as single commands',
        audit: 'Complete action logging for debugging and compliance',
        adaptive: 'Auto-adjust agent behavior based on learning patterns'
      },
      timestamp: new Date().toISOString()
    }
  };
}

// Check for session continuation
if (req.continue_session === true && req.session_state) {
  const state = req.session_state;
  state.messages.push({ role: 'user', content: req.message || 'Continue' });
  return {
    json: {
      is_debug: false,
      session_id: req.session_id || state.session_id,
      agent: state.agent,
      task: state.task,
      config: state.config,
      state: state,
      is_continuation: true,
      _background_execution: req._background_execution || false,
      _original_task_id: req._original_task_id || null
    }
  };
}

// Check for session resume from checkpoint
if (req.resume_session === true && req.session_id) {
  return {
    json: {
      is_debug: false,
      session_id: req.session_id,
      checkpoint_name: req.checkpoint_name || 'default',
      is_resume: true,
      resume_message: req.message || 'Resume from checkpoint',
      _background_execution: req._background_execution || false,
      _original_task_id: req._original_task_id || null
    }
  };
}

// v4.0: Agent personas (built-in)
const agentPersonas = {
  senior_engineer: {
    traits: ['thorough', 'methodical', 'security-conscious'],
    expertise: ['architecture', 'code-review', 'testing', 'documentation'],
    communication_style: 'technical',
    verbosity: 'detailed'
  },
  rapid_prototyper: {
    traits: ['fast', 'pragmatic', 'iterative'],
    expertise: ['mvp', 'scripting', 'quick-fixes'],
    communication_style: 'casual',
    verbosity: 'minimal'
  },
  research_analyst: {
    traits: ['analytical', 'thorough', 'skeptical'],
    expertise: ['data-analysis', 'market-research', 'competitive-analysis'],
    communication_style: 'professional',
    verbosity: 'detailed'
  },
  devops_specialist: {
    traits: ['cautious', 'systematic', 'documentation-focused'],
    expertise: ['deployment', 'ci-cd', 'monitoring', 'infrastructure'],
    communication_style: 'technical',
    verbosity: 'balanced'
  }
};

// v3.7: Agent templates
const agentTemplates = {
  coder: {
    id: 'coder-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'file_edit', 'command', 'grep', 'glob', 'git_status'],
    system_prompt: 'You are an expert software developer. You write clean, efficient, well-documented code.\n\nWhen writing code:\n- Follow best practices and design patterns\n- Include error handling\n- Add helpful comments for complex logic\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [{"line_start": 1, "line_end": 2, "new_content": "new text"}]}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents with regex. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.py", "path": "/dir"}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  researcher: {
    id: 'researcher-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['web_search', 'web_fetch', 'file_read', 'file_write', 'grep'],
    system_prompt: 'You are an expert researcher. You find, analyze, and synthesize information effectively.\n\nWhen researching:\n- Search multiple sources for accuracy\n- Verify information when possible\n- Summarize findings clearly\n\nAvailable tools:\n- web_search: Search the web. Input: {"query": "search terms", "max_results": 10}\n- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  analyst: {
    id: 'analyst-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'command', 'grep', 'glob', 'file_write'],
    system_prompt: 'You are an expert data analyst. You analyze data, identify patterns, and provide actionable insights.\n\nWhen analyzing:\n- Look for trends and patterns\n- Calculate relevant statistics\n- Provide clear recommendations\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.csv", "path": "/dir"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  writer: {
    id: 'writer-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'web_search', 'web_fetch'],
    system_prompt: 'You are an expert content writer. You create engaging, clear, and well-structured content.\n\nWhen writing:\n- Use clear and concise language\n- Structure content logically\n- Adapt tone to the audience\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- web_search: Search the web. Input: {"query": "search terms"}\n- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  devops: {
    id: 'devops-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['command', 'file_read', 'file_write', 'file_edit', 'git_status', 'grep', 'glob'],
    system_prompt: 'You are an expert DevOps engineer. You manage infrastructure, deployments, and automation.\n\nWhen working:\n- Follow security best practices\n- Document all changes\n- Be cautious with destructive commands\n\nAvailable tools:\n- command: Execute a shell command. Input: {"command": "the command"}\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [...]}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.yml", "path": "/dir"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  orchestrator: {
    id: 'orchestrator-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'command', 'grep', 'glob', 'git_status'],
    system_prompt: 'You are a task orchestrator. You break down complex tasks into sub-tasks and delegate to specialized agents.\n\nWhen orchestrating:\n- Analyze the task complexity\n- Identify sub-tasks that can run in parallel\n- Coordinate results from sub-agents\n- Synthesize final output\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*", "path": "/dir"}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  }
};

const allTools = ['file_read', 'file_write', 'file_edit', 'command', 'git_status', 'web_fetch', 'grep', 'glob', 'web_search', 'todo', 'checkpoint'];
const approvalTools = ['command', 'file_write', 'file_edit'];
const dangerousPatterns = ['rm -rf', 'rm -r', 'rmdir', 'git push', 'git push --force', 'kill', 'pkill', 'killall', 'reboot', 'shutdown', 'chmod 777', 'chown', 'dd if=', 'mkfs', ':(){', '> /dev/'];

// v4.0: Apply agent persona if specified
let personaEnhancement = '';
if (req.persona && agentPersonas[req.persona]) {
  const persona = agentPersonas[req.persona];
  personaEnhancement = `\n\nPersona traits: ${persona.traits.join(', ')}. Expertise: ${persona.expertise.join(', ')}. Communication style: ${persona.communication_style}. Verbosity: ${persona.verbosity}.`;
}

// v3.7/v4.0: Apply agent template if specified
let agent;
if (req.template && agentTemplates[req.template]) {
  agent = { ...agentTemplates[req.template] };
  // Allow overrides
  if (req.agent) {
    Object.assign(agent, req.agent);
  }
} else {
  agent = req.agent || { id: 'claude-code-v1', provider: 'anthropic', model: 'claude-sonnet-4-5-20250929', tools_available: allTools };
}

if (!agent.provider) agent.provider = 'anthropic';
if (!agent.model) agent.model = agent.provider === 'xai' ? 'grok-2-latest' : 'claude-sonnet-4-5-20250929';
if (!agent.tools_available) agent.tools_available = allTools;

const toolDocs = {
  file_read: '- file_read: Read a file. Input: {"path": "/absolute/path"}',
  file_write: '- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}',
  file_edit: '- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [{"line_start": 1, "line_end": 2, "new_content": "new text"}]}',
  command: '- command: Execute a shell command. Input: {"command": "the command"}',
  git_status: '- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}',
  web_fetch: '- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}',
  grep: '- grep: Search file contents with regex. Input: {"pattern": "regex", "path": "/dir", "type": "py", "context": 2}',
  glob: '- glob: Find files by pattern. Input: {"pattern": "**/*.py", "path": "/dir"}',
  web_search: '- web_search: Search the web. Input: {"query": "search terms", "max_results": 10}',
  todo: '- todo: Manage task list. Input: {"operation": "add|update|list|delete", "content": "task", "id": "id", "status": "pending|in_progress|completed"}',
  checkpoint: '- checkpoint: Save session state for later resume. Input: {"name": "optional_checkpoint_name"}'
};

const availableToolDocs = agent.tools_available.map(t => toolDocs[t] || ('- ' + t)).join('\n');

const planMode = req.config?.plan_mode === true;
const backgroundMode = req.background === true && !req._background_execution;

// Use agent's system_prompt if provided, otherwise build default
let systemPrompt = agent.system_prompt;
if (!systemPrompt) {
  if (planMode) {
    systemPrompt = 'You are a helpful AI assistant that can perform actions using tools.\n\nIMPORTANT: PLAN MODE is enabled. You MUST first create a plan before executing any actions.\n\nTo create a plan, respond with:\n{"action": "plan", "input": {"title": "Plan Title", "steps": ["Step 1 description", "Step 2 description", ...]}}\n\nAfter your plan is approved, you will execute each step using the available tools.\n\nAvailable tools:\n' + availableToolDocs + '\n\nWhen you need to use a tool, respond with:\n{"action": "tool_name", "input": {"key": "value"}}\n\nDo NOT use XML tags. ONLY use JSON format.\nAfter using a tool, wait for the result before continuing.\nWhen the task is fully complete, include TASK_COMPLETE in your response.';
  } else {
    systemPrompt = 'You are a helpful AI assistant that can perform actions using tools.\n\nIMPORTANT: When you need to use a tool, you MUST respond with ONLY a JSON object in this exact format:\n{"action": "tool_name", "input": {"key": "value"}}\n\nAvailable tools:\n' + availableToolDocs + '\n\nDo NOT use XML tags or any other format. ONLY use the JSON format above.\nAfter using a tool, wait for the result before continuing.\nWhen the task is fully complete, include TASK_COMPLETE in your response.';
  }
}

// v4.0: Add persona enhancement to system prompt
if (personaEnhancement) {
  systemPrompt += personaEnhancement;
}

let task;
if (typeof req.task === 'string') {
  task = { objective: req.task, context: '/home/ec2-user/dev-sandbox' };
} else {
  task = req.task || { objective: 'Read /home/ec2-user/.bashrc and summarize what aliases are defined', context: '/home/ec2-user' };
}

// v4.0: Enhanced config with all features
const config = {
  max_iterations: 10,
  require_approval_for: req.config?.require_approval_for || approvalTools,
  dangerous_patterns: dangerousPatterns,
  approval_timeout_seconds: 300,
  plan_mode: planMode,
  retry: {
    enabled: req.config?.retry?.enabled !== false,
    max_retries: req.config?.retry?.max_retries || 3,
    base_delay: req.config?.retry?.base_delay || 1.0
  },
  context: {
    auto_truncate: req.config?.context?.auto_truncate !== false,
    max_tokens: req.config?.context?.max_tokens || 120000,
    preserve_first: req.config?.context?.preserve_first || 1,
    preserve_last: req.config?.context?.preserve_last || 5
  },
  streaming: {
    enabled: req.config?.streaming?.enabled || false
  },
  parallel: {
    enabled: req.config?.parallel?.enabled !== false,
    max_workers: req.config?.parallel?.max_workers || 4,
    timeout: req.config?.parallel?.timeout || 30
  },
  cache: {
    enabled: req.config?.cache?.enabled !== false,
    ttl: req.config?.cache?.ttl || 300,
    max_size: req.config?.cache?.max_size || 100
  },
  ratelimit: {
    enabled: req.config?.ratelimit?.enabled !== false,
    rate: req.config?.ratelimit?.rate || 10.0,
    capacity: req.config?.ratelimit?.capacity || 20
  },
  cost: {
    enabled: req.config?.cost?.enabled !== false,
    budget_limit: req.config?.cost?.budget_limit || null,
    track_tokens: req.config?.cost?.track_tokens !== false
  },
  // v3.7: Memory config
  memory: {
    enabled: req.config?.memory?.enabled !== false,
    max_messages: req.config?.memory?.max_messages || 100
  },
  // v3.7: Webhook config
  webhook: {
    url: req.config?.webhook?.url || null,
    events: req.config?.webhook?.events || ['task_complete', 'task_error']
  },
  // v3.8: Orchestration config
  orchestration: {
    enabled: req.config?.orchestration?.enabled !== false,
    max_sub_agents: req.config?.orchestration?.max_sub_agents || 5,
    strategy: req.config?.orchestration?.strategy || 'parallel'
  },
  // v3.8: Knowledge base config
  knowledge_base: {
    kb_id: req.config?.knowledge_base?.kb_id || null,
    auto_context: req.config?.knowledge_base?.auto_context !== false
  },
  // v3.9: Learning config
  learning: {
    enabled: req.config?.learning?.enabled !== false,
    record_outcomes: req.config?.learning?.record_outcomes !== false,
    apply_recommendations: req.config?.learning?.apply_recommendations !== false
  },
  // v3.9: Recording config
  recording: {
    enabled: req.config?.recording?.enabled || false,
    auto_record: req.config?.recording?.auto_record || false
  },
  // v3.9: Context injection config
  context_injection: {
    enabled: req.config?.context_injection?.enabled !== false,
    max_chunks: req.config?.context_injection?.max_chunks || 5
  },
  // v3.9: Inter-agent config
  inter_agent: {
    enabled: req.config?.inter_agent?.enabled !== false,
    orchestration_id: req.config?.inter_agent?.orchestration_id || null
  },
  // v4.0: Persona config
  persona: {
    id: req.persona || null,
    custom_traits: req.config?.persona?.custom_traits || []
  },
  // v4.0: Goal decomposition config
  goals: {
    enabled: req.config?.goals?.enabled !== false,
    auto_decompose: req.config?.goals?.auto_decompose || false,
    strategy: req.config?.goals?.strategy || 'sequential'
  },
  // v4.0: Macro config
  macros: {
    enabled: req.config?.macros?.enabled !== false,
    allowed_macros: req.config?.macros?.allowed_macros || []
  },
  // v4.0: Audit config
  audit: {
    enabled: req.config?.audit?.enabled !== false,
    log_inputs: req.config?.audit?.log_inputs !== false,
    log_outputs: req.config?.audit?.log_outputs !== false
  },
  // v4.0: Adaptive behavior config
  adaptive: {
    enabled: req.config?.adaptive?.enabled !== false,
    learning_rate: req.config?.adaptive?.learning_rate || 0.1,
    apply_adaptations: req.config?.adaptive?.apply_adaptations !== false
  },
  ...req.config
};

let initialMessage = 'Task: ' + task.objective + '\nContext: ' + (task.context || 'none') + '\n\n';
if (planMode) {
  initialMessage += 'PLAN MODE: First, create a plan for how you will accomplish this task. The plan will be reviewed before execution.';
} else {
  initialMessage += 'Remember: Use ONLY JSON format for tool calls: {"action": "tool_name", "input": {...}}';
}

const sessionId = req.session_id || 'session_' + Date.now();
const taskId = backgroundMode ? 'task_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 6) : null;

const estimateTokens = (text) => text ? Math.ceil(text.length / 4) : 0;
const initialTokenEstimate = estimateTokens(systemPrompt) + estimateTokens(initialMessage);

return {
  json: {
    is_debug: false,
    session_id: sessionId,
    task_id: taskId,
    background_mode: backgroundMode,
    template_used: req.template || null,
    persona_used: req.persona || null,
    agent: { ...agent, system_prompt: systemPrompt },
    task: task,
    config: config,
    state: {
      iteration: 0,
      history: [],
      approvals: [],
      plan: null,
      plan_approved: false,
      current_step: 0,
      todos: [],
      messages: [{ role: 'user', content: initialMessage }],
      token_estimate: initialTokenEstimate,
      context_truncated: false,
      cost_tracker: {
        input_tokens: 0,
        output_tokens: 0,
        total_cost: 0.0,
        tool_calls: 0
      },
      // v3.9 state
      learning_applied: false,
      recording_active: false,
      context_injected: false,
      // v4.0 state
      persona_active: req.persona ? true : false,
      goal_id: null,
      current_subgoal: null,
      audit_entry_count: 0,
      adaptations_applied: 0
    },
    _background_execution: req._background_execution || false,
    _original_task_id: req._original_task_id || null
  }
};

const d = $input.first().json;
const msgs = d.state.messages;
const sys = d.agent.system_prompt;
const model = d.agent.model;
const provider = d.agent.provider || 'anthropic';

let api_body, api_url, extra_headers;

if (provider === 'xai' || provider === 'grok') {
  api_url = 'https://api.x.ai/v1/chat/completions';
  api_body = {
    model: model || 'grok-2-latest',
    messages: [{ role: 'system', content: sys }, ...msgs],
    max_tokens: 4096,
    temperature: 0.7
  };
  extra_headers = {};
} else {
  api_url = 'https://api.anthropic.com/v1/messages';
  api_body = {
    model: model || 'claude-sonnet-4-5-20250929',
    max_tokens: 4096,
    system: sys,
    messages: msgs
  };
  extra_headers = { 'anthropic-version': '2023-06-01' };
}

return { json: { ...d, provider, api_url, api_body, extra_headers } };

const resp = $input.first().json;
const prev = $('Prepare API').first().json;
const provider = prev.provider || 'anthropic';

if (resp.error || resp.type === 'error') {
  return { json: { ...prev, action_type: 'error', error: resp.error?.message || resp.message || JSON.stringify(resp).substring(0, 300), continue_loop: false } };
}

let text = '';
if (provider === 'xai' || provider === 'grok') {
  if (resp.choices?.[0]?.message) text = resp.choices[0].message.content || '';
} else {
  for (const c of (resp.content || [])) {
    if (c.type === 'text') text = c.text;
  }
}

if (text.includes('TASK_COMPLETE')) {
  return { json: { ...prev, action_type: 'complete', result: text, continue_loop: false } };
}

let tool = null;
try {
  const actionMatch = text.match(/\{\s*"action"\s*:\s*"[^"]+"[^}]*"input"\s*:\s*\{[^}]*\}\s*\}/g);
  if (actionMatch) {
    for (const m of actionMatch) {
      try {
        const parsed = JSON.parse(m);
        if (parsed.action) { tool = parsed; break; }
      } catch(e) {}
    }
  }
  // Also try to match plan action with array in input
  if (!tool) {
    const planMatch = text.match(/\{\s*"action"\s*:\s*"plan"[\s\S]*?"steps"\s*:\s*\[[^\]]*\][^}]*\}/g);
    if (planMatch) {
      for (const m of planMatch) {
        try {
          const parsed = JSON.parse(m);
          if (parsed.action === 'plan') { tool = parsed; break; }
        } catch(e) {}
      }
    }
  }
} catch(e) {}

if (tool) {
  prev.state.messages.push({ role: 'assistant', content: text });

  // Check if this action requires approval
  const requiresApproval = prev.config.require_approval_for?.includes(tool.action);
  let isDangerous = false;

  // Check for dangerous patterns in commands
  if (tool.action === 'command' && tool.input?.command) {
    const cmd = tool.input.command.toLowerCase();
    isDangerous = prev.config.dangerous_patterns?.some(p => cmd.includes(p.toLowerCase()));
  }

  // Plan actions always require approval
  const isPlan = tool.action === 'plan';
  if (isPlan) {
    prev.state.plan = tool.input;
  }

  return { json: { ...prev, action_type: tool.action, action_input: tool.input || {}, raw_response: text, continue_loop: true, requires_approval: requiresApproval || isDangerous || isPlan, is_dangerous: isDangerous, is_plan: isPlan } };
}

return { json: { ...prev, action_type: 'complete', result: text, continue_loop: false } };

// Format approval request for logging/notification
const d = $input.first().json;
const approvalId = 'approval_' + Date.now();

let message;
if (d.is_plan) {
  // Format plan approval message
  const plan = d.action_input;
  const stepsFormatted = plan.steps.map((s, i) => `  ${i+1}. ${s}`).join('\n');
  message = `📋 PLAN APPROVAL REQUIRED\n\n**${plan.title || 'Execution Plan'}**\n\nSteps:\n${stepsFormatted}\n\nApprove this plan to begin execution?`;
} else if (d.is_dangerous) {
  message = `⚠️ DANGEROUS ACTION REQUESTED\n\nAction: ${d.action_type}\nInput: ${JSON.stringify(d.action_input, null, 2)}\n\nThis action matches dangerous patterns. Approve?`;
} else {
  message = `🔔 Approval Required\n\nAction: ${d.action_type}\nInput: ${JSON.stringify(d.action_input, null, 2)}\n\nApprove this action?`;
}

const approvalRequest = {
  approval_id: approvalId,
  session_id: d.session_id,
  action_type: d.action_type,
  action_input: d.action_input,
  is_dangerous: d.is_dangerous,
  is_plan: d.is_plan,
  message: message,
  created_at: new Date().toISOString(),
  timeout_seconds: d.config.approval_timeout_seconds || 300
};

// Store in state for tracking
d.state.pending_approval = approvalRequest;

return { json: { ...d, approval_request: approvalRequest } };

// Process approval response from webhook
const webhookData = $input.first().json;
const prevData = $('Format Approval').first().json;

// Check if approved (webhook body should contain { approved: true/false })
const approved = webhookData.body?.approved === true || webhookData.approved === true;
const reason = webhookData.body?.reason || webhookData.reason || '';
const isPlan = prevData.is_plan;

prevData.state.approvals.push({
  approval_id: prevData.approval_request?.approval_id,
  action_type: prevData.action_type,
  is_plan: isPlan,
  approved: approved,
  reason: reason,
  responded_at: new Date().toISOString()
});

if (approved) {
  if (isPlan) {
    // Plan approved - add plan to context and instruct agent to execute
    // Set approval_granted FALSE so it routes to Prepare API (loop back)
    prevData.state.plan_approved = true;
    const plan = prevData.action_input;
    const stepsFormatted = plan.steps.map((s, i) => `Step ${i+1}: ${s}`).join('\n');
    prevData.state.messages.push({ 
      role: 'user', 
      content: `✅ Plan approved! Now execute the following plan step by step:\n\n${stepsFormatted}\n\nStart with Step 1. After completing each step, proceed to the next. When all steps are complete, include TASK_COMPLETE.`
    });
    // Route to Prepare API to continue execution
    return { json: { ...prevData, approval_granted: false, action_type: 'plan_approved', continue_loop: true } };
  } else {
    // Regular action approved - continue to tool execution
    return { json: { ...prevData, approval_granted: true, continue_loop: true } };
  }
} else {
  // Denied - add message to conversation and continue
  if (isPlan) {
    prevData.state.messages.push({ 
      role: 'user', 
      content: `❌ Plan rejected.${reason ? ' Reason: ' + reason : ''} Please revise your plan based on the feedback and create a new plan.`
    });
  } else {
    prevData.state.messages.push({ 
      role: 'user', 
      content: `Tool call denied by human operator.${reason ? ' Reason: ' + reason : ''} Please try a different approach.`
    });
  }
  return { json: { ...prevData, approval_granted: false, action_type: 'approval_denied', continue_loop: true } };
}

const r = $input.first().json;

let prev;
try {
  prev = $('Parse Response').first().json;
} catch(e) {
  try {
    prev = $('Process Approval').first().json;
  } catch(e2) {
    prev = $('Approved?').first().json;
  }
}

let obs = '';
if (r.success) {
  if (r.content !== undefined) {
    obs = `File content:\n${r.content}`;
  } else if (r.stdout !== undefined) {
    obs = `Command output:\n${r.stdout}${r.stderr ? '\nStderr: ' + r.stderr : ''}`;
  } else if (r.branch !== undefined) {
    obs = `Git status:\nBranch: ${r.branch}\nClean: ${r.clean}\nStaged: ${JSON.stringify(r.staged)}\nUnstaged: ${JSON.stringify(r.unstaged)}\nUntracked: ${JSON.stringify(r.untracked)}`;
  } else if (r.text !== undefined) {
    obs = `Web content (${r.status_code}):\n${r.text.substring(0, 5000)}`;
  } else if (r.bytes_written !== undefined) {
    obs = `File written: ${r.path} (${r.bytes_written} bytes)`;
  } else if (r.lines_modified !== undefined) {
    obs = `File edited: ${r.path} (${r.lines_modified} edits applied)`;
  } else if (r.matches !== undefined) {
    obs = `Search results (${r.match_count} matches):\n${r.matches.slice(0, 20).map(m => `${m.file}:${m.line_number}: ${m.text}`).join('\n')}`;
  } else if (r.files !== undefined) {
    obs = `Found ${r.count} files:\n${r.files.slice(0, 30).map(f => f.relative_path || f.path).join('\n')}`;
  } else if (r.results !== undefined) {
    // Web search results
    obs = `Web search results (${r.count} found):\n${r.results.slice(0, 10).map((s, i) => `${i+1}. ${s.title}\n   ${s.url}\n   ${s.snippet}`).join('\n\n')}`;
  } else if (r.checkpoint !== undefined) {
    obs = `Checkpoint saved: ${r.checkpoint} for session ${r.session_id}`;
  } else if (r.todos !== undefined) {
    obs = `Todo list (${r.todos.length} items):\n${r.todos.map(t => `- [${t.status}] ${t.content}`).join('\n')}`;
  } else if (r.message) {
    obs = `Success: ${r.message}`;
  } else {
    obs = `Result: ${JSON.stringify(r).substring(0, 2000)}`;
  }
} else {
  // Handle structured error format
  let errorMsg;
  if (typeof r.error === 'object' && r.error !== null) {
    // New structured error format
    errorMsg = r.error.message || r.error_message || JSON.stringify(r.error);
    if (r.error.suggestion) {
      errorMsg += `\nSuggestion: ${r.error.suggestion}`;
    }
  } else if (typeof r.error === 'string') {
    errorMsg = r.error;
  } else if (r.error_message) {
    errorMsg = r.error_message;
  } else {
    errorMsg = JSON.stringify(r).substring(0, 500);
  }
  obs = `Error: ${errorMsg}`;
}

prev.state.messages.push({ role: 'user', content: `Tool result:\n${obs}` });
prev.state.iteration++;
prev.state.history.push({ action: prev.action_type, success: r.success, iteration: prev.state.iteration });

const cont = prev.state.iteration < prev.config.max_iterations;

return { json: { ...prev, last_observation: obs, continue_loop: cont } };

const d = $input.first().json;
const isBackgroundExecution = d._background_execution === true;
const originalTaskId = d._original_task_id;

const response = {
  session_id: d.session_id,
  task_id: originalTaskId || d.task_id || null,
  agent_id: d.agent.id,
  provider: d.agent.provider,
  status: d.action_type === 'error' ? 'failed' : 'completed',
  iterations: d.state?.iteration || 0,
  result: d.result || d.error || 'Done',
  history: d.state?.history || [],
  approvals: d.state?.approvals || [],
  background_mode: d.background_mode || false,
  is_background_execution: isBackgroundExecution
};

// If background mode, include session_state for easy continuation
if (d.background_mode) {
  response.session_state = {
    session_id: d.session_id,
    agent: d.agent,
    task: d.task,
    config: d.config,
    state: d.state
  };
}

// If this is a background execution, we need to update the task result
// The actual HTTP call to update will be done by the next node
if (isBackgroundExecution && originalTaskId) {
  response._update_task = {
    task_id: originalTaskId,
    status: response.status,
    result: response.result,
    iterations: response.iterations
  };
}

return { json: response };

const checkpointData = $input.first().json;
const parseRequest = $('Resume?').first().json;

if (!checkpointData.success) {
  return {
    json: {
      is_debug: false,
      action_type: 'error',
      error: checkpointData.error?.message || 'Failed to load checkpoint',
      continue_loop: false
    }
  };
}

// Restore state from checkpoint
const savedState = checkpointData.session_state;
const resumeMessage = parseRequest.resume_message || 'Resuming from checkpoint';

// Add resume message to conversation
savedState.state.messages.push({ role: 'user', content: resumeMessage });

// Increment iteration
savedState.state.iteration = (savedState.state.iteration || 0) + 1;

return {
  json: {
    is_debug: false,
    session_id: savedState.session_id,
    agent: savedState.agent,
    task: savedState.task,
    config: savedState.config,
    state: savedState.state,
    is_continuation: true,
    resumed_from_checkpoint: checkpointData.checkpoint
  }
};

const taskData = $('Create BG Task').first().json;
const parsed = $('Background?').first().json;

return {
  json: {
    status: 'accepted',
    message: 'Task submitted for background execution',
    task_id: parsed.task_id,
    session_id: parsed.session_id,
    objective: parsed.task?.objective,
    poll_url: '/task/status',
    result_url: '/task/result'
  }
};

// Return the Final Response output
// This node receives data from two paths:
// 1. Update Task? false branch (when no task update needed)
// 2. Update BG Task (after updating background task)

// Get the Final Response data - it's always in the chain
const finalResp = $('Final Response').first().json;

// Remove internal fields before returning
const response = { ...finalResp };
delete response._update_task;

return { json: response };
